    private bool        _panelOpen   = false;
    private bool        _loading     = false;
    private int         _unreadCount = 0;
    private List<NotificationDto> _notifications = [];

    protected override async Task OnInitializedAsync()
    {
        NotifService.Subscribe(OnNotificationReceivedAsync);
        Navigation.LocationChanged += OnLocationChangedAsync;
        await RefreshUnreadCountAsync();
    }

    private async void OnLocationChangedAsync(object? sender, Microsoft.AspNetCore.Components.Routing.LocationChangedEventArgs e)
    {
        _panelOpen = false;
        await RefreshUnreadCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnNotificationReceivedAsync()
    {
        await RefreshUnreadCountAsync();
        if (_panelOpen)
            await LoadNotificationsAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task TogglePanel()
    {
        _panelOpen = !_panelOpen;
        if (_panelOpen)
            await LoadNotificationsAsync();
    }

    private void ClosePanel() => _panelOpen = false;

    private async Task LoadNotificationsAsync()
    {
        _loading = true;
        StateHasChanged();

        var result = await NotifService.GetNotificationsAsync(includeRead: true);
        if (result.IsSuccess)
            _notifications = result.Value;

        _loading = false;
        await RefreshUnreadCountAsync();
        StateHasChanged();
    }

    private async Task RefreshUnreadCountAsync()
    {
        var result = await NotifService.GetUnreadCountAsync();
        if (result.IsSuccess)
            _unreadCount = result.Value;
    }

    private async Task MarkAsReadAsync(Guid id)
    {
        await NotifService.MarkAsReadAsync(id);
        var n = _notifications.FirstOrDefault(x => x.Id == id);
        if (n is not null)
        {
            var idx = _notifications.IndexOf(n);
            _notifications[idx] = n with { IsRead = true };
        }
        await RefreshUnreadCountAsync();
        StateHasChanged();
    }

    private async Task MarkAllAsReadAsync()
    {
        await NotifService.MarkAllAsReadAsync();
        _notifications = _notifications
            .Select(n => n with { IsRead = true })
            .ToList();
        _unreadCount = 0;
        StateHasChanged();
    }

    private async Task DeleteAsync(Guid id)
    {
        await NotifService.DeleteAsync(id);
        _notifications.RemoveAll(n => n.Id == id);
        await RefreshUnreadCountAsync();
        StateHasChanged();
    }

    private async Task HandleInteractionClickAsync(NotificationDto n)
    {
        if (!n.IsRead)
            await MarkAsReadAsync(n.Id);
        ClosePanel();
    }

    private async Task HandleServerActionAsync(NotificationDto n, string? actionName)
    {
        if (!n.IsRead)
            await MarkAsReadAsync(n.Id);
        if (actionName is not null)
            Navigation.NavigateTo($"/notifications/action?name={Uri.EscapeDataString(actionName)}&notificationId={n.Id}");
        ClosePanel();
    }

    // ── Hilfsmethoden ─────────────────────────────────────────────────────────

    private static Color GetSeverityColor(string severity) => severity switch
    {
        "success" => Color.Success,
        "warning" => Color.Warning,
        "error"   => Color.Error,
        "notice"  => Color.Info,
        _         => Color.Default
    };

    private static string GetSeverityLabel(string severity) => severity switch
    {
        "success" => "Erfolg",
        "warning" => "Hinweis",
        "error"   => "Fehler",
        "notice"  => "Info",
        _         => "Info"
    };

    private static string GetItemStyle(NotificationDto n)
        => n.IsRead
            ? string.Empty
            : "background: var(--mud-palette-action-hover);";

    private static string GetTitleStyle(NotificationDto n)
        => n.IsRead ? "font-weight: 400;" : "font-weight: 600;";

    private static string FormatRelativeTime(DateTime createdAt)
    {
        var diff = DateTime.UtcNow - createdAt;
        return diff.TotalMinutes < 1    ? "Gerade eben"
             : diff.TotalHours   < 1    ? $"vor {(int)diff.TotalMinutes} Min."
             : diff.TotalDays    < 1    ? $"vor {(int)diff.TotalHours} Std."
             : diff.TotalDays    < 7    ? $"vor {(int)diff.TotalDays} Tagen"
             : createdAt.ToString("dd.MM.yyyy");
    }

    public void Dispose()
    {
        Navigation.LocationChanged -= OnLocationChangedAsync;
    }

    public async ValueTask DisposeAsync()
    {
        NotifService.Unsubscribe(OnNotificationReceivedAsync);
        Navigation.LocationChanged -= OnLocationChangedAsync;
        await Task.CompletedTask;
    }

